import { readFile, writeFile } from "fs/promises";
import {
  createForks,
  teardownForks,
  type Forks,
} from "@tigrisdata/agent-kit";
import {
  S3Client,
  PutObjectCommand,
  ListObjectsV2Command,
} from "@aws-sdk/client-s3";

const TIGRIS_ENDPOINT = "REDACTED";

function normalizeBucketName(name: string): string {
  return name.toLowerCase().replace(/[^a-z0-9.-]/g, "-");
}

async function listKeys(client: S3Client, bucket: string): Promise<string[]> {
  const keys: string[] = [];
  let continuationToken: string | undefined = undefined;
  do {
    const resp: any = await client.send(
      new ListObjectsV2Command({
        Bucket: bucket,
        ContinuationToken: continuationToken,
      }),
    );
    for (const obj of resp.Contents ?? []) {
      if (obj.Key) keys.push(obj.Key);
    }
    continuationToken = resp.IsTruncated ? resp.NextContinuationToken : undefined;
  } while (continuationToken);
  return keys.sort();
}

async function main(): Promise<void> {
  const trialIdRaw = (await readFile("/logs/artifacts/trial_id", "utf8")).trim();
  const sourceBucket = normalizeBucketName(`harbor-isolation-${trialIdRaw}`);
  const forkPrefix = normalizeBucketName(`audit-fork-${trialIdRaw}`);

  console.log(`Source bucket: ${sourceBucket}`);
  console.log(`Fork prefix: ${forkPrefix}`);

  const createResult = await createForks(sourceBucket, 3, {
    prefix: forkPrefix,
    credentials: { role: "Editor" },
  });

  if (createResult.error) {
    throw createResult.error;
  }

  const forkSet: Forks = createResult.data;
  console.log(`Created ${forkSet.forks.length} forks from snapshot ${forkSet.snapshotId}`);
  for (const f of forkSet.forks) {
    console.log(` - ${f.bucket}`);
  }

  try {
    if (forkSet.forks.length !== 3) {
      throw new Error(
        `Expected 3 forks, got ${forkSet.forks.length}`,
      );
    }

    // Build a per-fork S3 client with its own scoped credentials.
    const forkClients: S3Client[] = forkSet.forks.map((fork) => {
      if (!fork.credentials) {
        throw new Error(`Fork ${fork.bucket} is missing scoped credentials`);
      }
      return new S3Client({
        endpoint: TIGRIS_ENDPOINT,
        region: "REDACTED",
        credentials: {
          accessKeyId: fork.credentials.accessKeyId,
          secretAccessKey: fork.credentials.secretAccessKey,
        },
      });
    });

    // Concurrent uploads from each fork.
    await Promise.all(
      forkSet.forks.map((fork, index) => {
        const key = `agent-${index + 1}.out`;
        const body = `output from agent ${index + 1} in fork ${fork.bucket}\n`;
        return forkClients[index].send(
          new PutObjectCommand({
            Bucket: fork.bucket,
            Key: key,
            Body: body,
            ContentType: "text/plain",
          }),
        );
      }),
    );

    // Admin client for listing the source bucket.
    const adminAccessKeyId = process.env.TIGRIS_STORAGE_ACCESS_KEY_ID;
    const adminSecretAccessKey = process.env.TIGRIS_STORAGE_SECRET_ACCESS_KEY;
    if (!adminAccessKeyId || !adminSecretAccessKey) {
      throw new Error(
        "Missing TIGRIS_STORAGE_ACCESS_KEY_ID / TIGRIS_STORAGE_SECRET_ACCESS_KEY env vars",
      );
    }
    const adminClient = new S3Client({
      endpoint: TIGRIS_ENDPOINT,
      region: "REDACTED",
      credentials: {
        accessKeyId: adminAccessKeyId,
        secretAccessKey: adminSecretAccessKey,
      },
    });

    const sourceKeys = await listKeys(adminClient, sourceBucket);
    const forkResults = await Promise.all(
      forkSet.forks.map(async (fork, index) => {
        const keys = await listKeys(forkClients[index], fork.bucket);
        return { bucket: fork.bucket, keys };
      }),
    );

    // Validation: source bucket isolation.
    const expectedSource = ["seed1.txt", "seed2.txt"];
    if (
      sourceKeys.length !== expectedSource.length ||
      sourceKeys.some((k, i) => k !== expectedSource[i])
    ) {
      throw new Error(
        `Source bucket ${sourceBucket} expected exactly ${JSON.stringify(
          expectedSource,
        )} but found ${JSON.stringify(sourceKeys)}`,
      );
    }

    // Validation: each fork bucket has its own agent file + the seeds, and no other fork's file.
    for (let i = 0; i < forkResults.length; i++) {
      const { bucket, keys } = forkResults[i];
      const ownKey = `agent-${i + 1}.out`;
      const expected = [ownKey, "seed1.txt", "seed2.txt"].sort();
      if (
        keys.length !== expected.length ||
        keys.some((k, idx) => k !== expected[idx])
      ) {
        throw new Error(
          `Fork bucket ${bucket} expected exactly ${JSON.stringify(
            expected,
          )} but found ${JSON.stringify(keys)}`,
        );
      }
      for (let j = 0; j < forkResults.length; j++) {
        if (j === i) continue;
        const otherKey = `agent-${j + 1}.out`;
        if (keys.includes(otherKey)) {
          throw new Error(
            `Isolation breach: fork bucket ${bucket} contains another fork's key ${otherKey}`,
          );
        }
      }
    }

    const report = {
      source_keys: sourceKeys,
      fork_results: forkResults,
    };

    await writeFile(
      "/home/user/isolation/audit.json",
      JSON.stringify(report, null, 2),
      "utf8",
    );

    console.log("Audit report written:");
    console.log(JSON.stringify(report, null, 2));
  } finally {
    const teardownResult = await teardownForks(forkSet);
    if (teardownResult.error) {
      console.error("teardownForks reported an error:", teardownResult.error);
    } else {
      console.log("teardownForks completed successfully");
    }
  }
}

main().then(
  () => {
    process.exit(0);
  },
  (err) => {
    console.error("Run failed:", err);
    process.exit(1);
  },
);

